class MagixFormTools{constructor(){window.MagixFormToolsInitialized||(window.MagixFormToolsInitialized=!0,this.initUrlLocks(),this.initTagsDropdown())}initUrlLocks(){document.addEventListener("click",(t=>{const e=t.target.closest(".toggle-url-lock");if(!e)return;t.preventDefault();const n=e.getAttribute("data-target"),o=document.getElementById(n),i=e.querySelector("i");o&&(o.hasAttribute("readonly")?(o.removeAttribute("readonly"),o.classList.remove("bg-light"),i&&(i.classList.remove("bi-lock"),i.classList.add("bi-unlock","text-warning")),e.setAttribute("title","Verrouiller l'URL"),o.focus()):(o.setAttribute("readonly","readonly"),o.classList.add("bg-light"),i&&(i.classList.remove("bi-unlock","text-warning"),i.classList.add("bi-lock")),e.setAttribute("title","Déverrouiller l'URL")))}))}initTagsDropdown(){const t=document.getElementById("searchTagsInput"),e=document.getElementById("tags-count-text");if(!e)return;const n=document.querySelectorAll(".tag-item"),o=document.querySelectorAll(".tag-checkbox");t&&t.addEventListener("input",(t=>{const e=t.target.value.toLowerCase().trim();n.forEach((t=>{const n=t.textContent.toLowerCase();t.style.display=n.includes(e)?"":"none"}))}));const i=()=>{const t=document.querySelectorAll(".tag-checkbox:checked").length;if(0===t)e.textContent="Aucun tag sélectionné";else if(1===t){const t=document.querySelector(".tag-checkbox:checked");t&&t.nextElementSibling&&(e.textContent=t.nextElementSibling.textContent.trim())}else e.textContent=t+" tags sélectionnés"};o.forEach((t=>{t.addEventListener("change",i)})),i()}}